var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"대장님! 타깃을 확보했습니다!","JPN":"隊長！　ターゲットを確保しました！","ENG":"Captain, we've secured the target!","TWN":"隊長！已確定目標！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"흠냐, 음냐......","JPN":"むにゃぁ……すーぴー……","ENG":"Zzz... Zzz...","TWN":"呼嚕，呼嚕……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"좋아. 이번엔 깨지 않게 조심하라고.","JPN":"よし、今回は起こさないように気をつけろ。","ENG":"Alright, be careful not to wake her up this time.","TWN":"很好，這次小心別弄醒她。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"놈들이 다시 전열을 가다듬기 전에 곧바로 철수한다!","JPN":"やつらがまた戦列を整える前に撤収するぞ！","ENG":"We have to get out of here before they regroup!","TWN":"在對方重整隊形之前立刻撤退！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 뭐 하는 거죠? 철수라니, 이건 약속이랑 틀리잖아요!","JPN":"な、何をしてるんですか？　撤収って、これは約束と違います！","ENG":"W-what are you doing? You're not going anywhere—that's not what we agreed upon!","TWN":"你、你們在做什麼？說什麼撤退，這跟當初說的不一樣！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"이봐, 이 정도 시간을 번 것만으로도 굉장한 거야.","JPN":"これくらいの時間を稼げただけでもすごいことなんだ。","ENG":"Hey, it's a miracle that we stalled them this long.","TWN":"喂，我們能撐這麼久，已經算是很了不起了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"애초에 저런 카운터들을 상대로 고작 침식체 몇 마리가 돕는다고 이길 거라 생각한 건 아니겠지?","JPN":"そもそもあんなカウンターたちを相手に、侵食体数匹で勝てると思ったのか？","ENG":"You didn't think we could beat those Counters just because we have a few C.O.s on our side, did you?","TWN":"難道妳真的以為用幾隻侵蝕體，就能打敗那些制裁者嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"크으윽, 이 치사한!","JPN":"くっ、なんと卑怯な！","ENG":"Grr, you scoundrel!","TWN":"可惡，真是不要臉！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"아 참, 깜박할 뻔했군.","JPN":"あっ、忘れるところだった。","ENG":"Oh, I almost forgot.","TWN":"對了，差點忘了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"저 여자도 어서 챙겨.","JPN":"あの女も連れて行け。","ENG":"Pick her up, too.","TWN":"把那個女的也帶上。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"예? 아, 알겠습니다!","JPN":"はい？　わ、わかりました！","ENG":"Sorry? Oh, yes sir!","TWN":"啊？是，知道了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"으아아악?! 무슨 짓이야! 이거 놓지 못해!","JPN":"うわああっ！？　なっ、何をするの！　いやっ、離して！","ENG":"Wah?! What are you doing? Get off me!","TWN":"啊啊啊啊？！你們幹什麼！放開我！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"의뢰도 완수하고 뜻밖의 수확까지 거두다니. 횡재했어.","JPN":"依頼も成功し、予想外の収穫とは棚ぼただな。","ENG":"We accomplished our mission and picked up a bonus along the way. How lucky!","TWN":"不僅完成了委託，還有了意外收穫，真是大賺了一票。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"진짜 침식체를 조종할 줄 아는 능력자라면 꽤나 비싼 값에 넘길 수 있겠군.","JPN":"本当に侵食体を操れる能力者なら、かなりの高値で取引できそうだ。","ENG":"If she really has the ability to control C.O.s, she'll fetch a good price.","TWN":"能操控侵蝕體的能力者，應該能賣個好價錢吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"거기까지 생각해두셨다니 굉장하군요, 대장님! 진짜 악당들조차도 혀를 내두를 정도입니다.","JPN":"そこまで考えていたとはさすがです、隊長！　本物の悪党たちも舌を巻くほどです！","ENG":"Captain, you've thought that far ahead. Even the real villains would be disgusted by you!","TWN":"你竟然能想到這一步，真是太了不起了！真正的反派也一定會對你五體投地的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"시끄러워! 어서 이륙이나 해!","JPN":"うるさい、今すぐ離陸しろ！","ENG":"Shut up! Just take off already!","TWN":"吵死了！快起飛！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};